// Deploy ANY contract through DeployerFactory on Base — no creation tx needed.
// initCode = creation bytecode ++ ABI-encoded constructor args (what a creation tx would carry).
import { createWalletClient, createPublicClient, http, encodeFunctionData, parseAbi } from "viem";
import { privateKeyToAccount } from "viem/accounts";
import { base } from "viem/chains";

const FACTORY = "0xCF4357aFdC26fa028e77291CE2F97C9dAF93F75D"; // DeployerFactory on Base (8453)
const abi = parseAbi([
  "function deploy(bytes initCode) payable returns (address)",
  "function fee() view returns (uint256)",
  "event Deployed(address indexed deployer, address indexed addr, uint256 feePaid)",
]);

const account = privateKeyToAccount(process.env.PRIVATE_KEY as `0x${string}`);
const pub = createPublicClient({ chain: base, transport: http() });
const wallet = createWalletClient({ account, chain: base, transport: http() });

const initCode = process.env.INIT_CODE as `0x${string}`; // your compiled creation bytecode (+ ctor args)
const fee = await pub.readContract({ address: FACTORY, abi, functionName: "fee" });

const hash = await wallet.sendTransaction({
  to: FACTORY,
  value: fee, // send exactly the fee unless your constructor is payable
  data: encodeFunctionData({ abi, functionName: "deploy", args: [initCode] }),
});
const receipt = await pub.waitForTransactionReceipt({ hash });
const log = receipt.logs.find((l) => l.address.toLowerCase() === FACTORY.toLowerCase());
const deployed = "0x" + log!.topics[2]!.slice(26); // Deployed event: topics[2] = new address
console.log("deployed at:", deployed);
if ((await pub.getCode({ address: deployed as `0x${string}` })) === undefined) throw new Error("no code — verify failed");
